108→// Function to find the chat input
109→function getChatInput(): HTMLElement | null {
110→  // Gemini usually has a rich-textarea
111→  // Try multiple selectors from most specific to generic
112→  const selectors = [
113→    'rich-textarea [contenteditable="true"]',
114→    'div[contenteditable="true"][role="textbox"]',
115→    '.input-area textarea',
116→    'textarea[placeholder*="Ask"]',
117→    'textarea', // Fallback, might be dangerous
118→  ];
119→
120→  for (const selector of selectors) {
121→    // We probably want the one in the main footer/input area, not others (like edit mode)
122→    // Usually the main input is visible and larger.
123→    const els = document.querySelectorAll(selector);
124→    for (const el of Array.from(els)) {
125→      // Check if it's visible
126→      if (el.getBoundingClientRect().height > 0) {
127→        return el as HTMLElement;
128→      }
129→    }
130→  }
131→  return null;
132→}
133→
134→function countLineBreaks(raw: string): number {
135→  return (raw.match(/\n/g) || []).length;
136→}
137→
138→interface SeparatorInsertResult {
139→  inserted: boolean;
140→  insertedBreaks: number;
141→}
142→
143→function getContenteditableQuoteSeparator(): string {
144→  // Firefox + Quill contenteditable tends to render an extra visual break
145→  // for double-newline insertion, so we use a single newline separator there.
146→  return getBrowserName() === 'Firefox' ? '\n' : '\n\n';
147→}
148→
149→function getPlaceholderCandidates(input: HTMLElement): string[] {
150→  const richTextarea = input.closest('rich-textarea');
151→  const candidates = [
152→    input.getAttribute('data-placeholder'),
153→    input.getAttribute('aria-placeholder'),
154→    input.getAttribute('placeholder'),
155→    richTextarea?.getAttribute('data-placeholder'),
156→    richTextarea?.getAttribute('aria-placeholder'),
157→    richTextarea?.getAttribute('placeholder'),
158→  ];
159→
160→  return candidates.filter((value): value is string => Boolean(value)).map((value) => value.trim());
161→}
162→
163→function isChatInputEmpty(input: HTMLElement | HTMLTextAreaElement): boolean {
164→  if (input instanceof HTMLTextAreaElement) {
165→    return input.value.trim().length === 0;
166→  }
167→
168→  const rawContent = input.innerText ?? input.textContent ?? '';
169→  const trimmedContent = rawContent.trim();
170→
171→  // If visible text exists and it's not placeholder text, treat as non-empty even if
172→  // Quill's `ql-blank` class lags behind DOM updates.
173→  if (trimmedContent.length > 0) {
174→    const placeholders = getPlaceholderCandidates(input);
175→    const isPlaceholderText = placeholders.some(
176→      (placeholder) => placeholder.length > 0 && placeholder === trimmedContent,
177→    );
178→    if (!isPlaceholderText) {
179→      return false;
180→    }
181→  }
182→
183→  // Gemini currently uses Quill internals. `ql-blank` is its canonical empty marker.
184→  if (input.classList.contains('ql-blank')) {
185→    return true;
186→  }
187→
188→  return trimmedContent.length === 0;
189→}
190→
191→/**
192→ * Attempts to insert separator text via execCommand and reports whether
193→ * content changed plus how many line breaks were observed as inserted.
194→ */
195→function tryInsertQuoteSeparator(input: HTMLElement, separator: string): SeparatorInsertResult {
196→  const beforeVisible = input.innerText ?? '';
197→  const beforeRaw = input.textContent ?? '';
198→  const beforeVisibleLineBreakCount = countLineBreaks(beforeVisible);
199→  const beforeRawLineBreakCount = countLineBreaks(beforeRaw);
200→  let ok = false;
201→  try {
202→    ok = document.execCommand('insertText', false, separator);
203→  } catch {
204→    ok = false;
205→  }
206→  if (!ok) return { inserted: false, insertedBreaks: 0 };
207→
208→  const afterVisible = input.innerText ?? '';
209→  const afterRaw = input.textContent ?? '';
210→  if (afterVisible === beforeVisible && afterRaw === beforeRaw) {
211→    return { inserted: false, insertedBreaks: 0 };
212→  }
213→
214→  const visibleLineBreakDelta = countLineBreaks(afterVisible) - beforeVisibleLineBreakCount;
215→  const rawLineBreakDelta = countLineBreaks(afterRaw) - beforeRawLineBreakCount;
216→  const insertedBreaks = Math.max(0, visibleLineBreakDelta, rawLineBreakDelta);
217→  return { inserted: true, insertedBreaks };
218→}
