  7→const STYLE_ID = 'gemini-voyager-input-collapse';
  8→const COLLAPSED_CLASS = 'gv-input-collapsed';
  9→const PLACEHOLDER_CLASS = 'gv-collapse-placeholder';
 10→
 11→/**
 12→ * Checks if the current page is the homepage or a new conversation page.
 13→ * These pages have the URL pattern /app or /u/<num>/app without a conversation ID.
 14→ * Examples of homepage/new conversation:
 15→ *   - /app
 16→ *   - /u/0/app
 17→ *   - /u/1/app
 18→ * Examples of existing conversations (should NOT match):
 19→ *   - /app/abc123def456
 20→ *   - /u/0/app/abc123def456
 21→ *   - /gem/xxx/abc123
 22→ */
 23→function isHomepageOrNewConversation(): boolean {
 24→  const pathname = window.location.pathname;
 25→  // Match /app or /u/<num>/app exactly (no conversation ID after /app)
 26→  // Must NOT have anything after /app except optional trailing slash
 27→  return /^\/(?:u\/\d+\/)?app\/?$/.test(pathname);
 28→}
 29→
 30→/**
 31→ * Checks if the current page is a gems editor page (create or edit).
 32→ * These pages should not have auto-collapse behavior.
 33→ */
 34→function isGemsEditorPage(): boolean {
 35→  const pathname = window.location.pathname;
 36→  // Match /gems/create, /gems/edit/*, or /u/<num>/gems/create, /u/<num>/gems/edit/*
 37→  return /^\/(?:u\/\d+\/)?gems\/(?:create|edit)\/?/.test(pathname);
 38→}
 39→
 40→/**
 41→ * Checks if auto-collapse should be disabled on the current page.
 42→ */
 43→function shouldDisableAutoCollapse(): boolean {
 44→  return isHomepageOrNewConversation() || isGemsEditorPage();
 45→}
