 60→
 61→    /* 
 62→     * Collapsed State Styles
 63→     */
 64→    .${COLLAPSED_CLASS} {
 65→      /* Compact dimensions */
 66→      height: 48px !important;
 67→      min-height: 48px !important;
 68→      max-height: 48px !important;
 69→      
 70→      /* Pill shape */
 71→      border-radius: 24px !important;
