171→ * We need the container that holds the background color and the full width.
172→ */
173→function getInputContainer(): HTMLElement | null {
174→  // Safety check for test environments and edge cases
175→  if (typeof document === 'undefined') return null;
176→
177→  const textarea = document.querySelector('rich-textarea');
178→  if (!textarea) return null;
179→
180→  let current = textarea.parentElement;
181→  let bestCandidate: HTMLElement | null = null;
182→
183→  // Traverse up to 8 levels
184→  for (let i = 0; i < 8; i++) {
185→    if (!current) break;
186→
187→    // Check computed style for background color to find the visual "island"
188→    const style = window.getComputedStyle(current);
189→    const hasBackground =
190→      style.backgroundColor !== 'rgba(0, 0, 0, 0)' && style.backgroundColor !== 'transparent';
191→    const isFlex = style.display.includes('flex');
192→
193→    // Check for specific Gemini/Material classes or roles
194→    // We prioritize the container that has a background color
195→    if (hasBackground) {
196→      bestCandidate = current as HTMLElement;
197→      // If we found a substantial container (flex + background), it's a strong candidate.
198→      if (isFlex) {
199→        // Continue one more level just in case there's a wrapper, but update bestCandidate
200→      }
201→    }
202→
203→    // Stop if we hit the limit or dangerous nodes
204→    if (
205→      current.tagName === 'MAIN' ||
206→      current.tagName === 'BODY' ||
207→      current.classList.contains('content-wrapper')
208→    ) {
209→      break;
210→    }
211→
212→    current = current.parentElement;
213→  }
214→
215→  // If we found a candidate with a background, use it.
216→  // Otherwise fallback to heuristic parents.
217→  return bestCandidate || textarea.parentElement?.parentElement || textarea.parentElement;
218→}
