299→export function startInputCollapse() {
300→  // Check if feature is enabled (default: false)
301→  chrome.storage?.sync?.get(
302→    {
303→      [StorageKeys.INPUT_COLLAPSE_ENABLED]: false,
304→      [StorageKeys.INPUT_COLLAPSE_WHEN_NOT_EMPTY]: false,
305→    },
306→    (res) => {
307→      if (res?.[StorageKeys.INPUT_COLLAPSE_ENABLED] === false) {
308→        // Feature is disabled, don't initialize
309→        return;
310→      }
311→
312→      // Feature is enabled, proceed with initialization
313→      initInputCollapse(res?.[StorageKeys.INPUT_COLLAPSE_WHEN_NOT_EMPTY] === true);
314→    },
315→  );
316→
317→  // Listen for setting changes
318→  chrome.storage?.onChanged?.addListener((changes, area) => {
319→    if (area !== 'sync') return;
320→    if (
321→      !changes[StorageKeys.INPUT_COLLAPSE_ENABLED] &&
322→      !changes[StorageKeys.INPUT_COLLAPSE_WHEN_NOT_EMPTY]
323→    )
324→      return;
325→
326→    if (changes[StorageKeys.INPUT_COLLAPSE_ENABLED]?.newValue === false) {
327→      // Disable: remove styles and classes
328→      cleanup();
329→      return;
330→    }
331→
332→    if (changes[StorageKeys.INPUT_COLLAPSE_WHEN_NOT_EMPTY]) {
333→      // Update the setting in-place (no need to re-initialize)
334→      allowCollapseWhenNotEmpty =
335→        changes[StorageKeys.INPUT_COLLAPSE_WHEN_NOT_EMPTY].newValue === true;
336→    }
337→
338→    if (changes[StorageKeys.INPUT_COLLAPSE_ENABLED]?.newValue === true) {
339→      // Enable: initialize with current sub-setting
340→      chrome.storage?.sync?.get({ [StorageKeys.INPUT_COLLAPSE_WHEN_NOT_EMPTY]: false }, (res) => {
341→        initInputCollapse(res?.[StorageKeys.INPUT_COLLAPSE_WHEN_NOT_EMPTY] === true);
342→      });
343→    }
344→  });
345→}
