353→/**
354→ * Cleans up the input collapse feature.
355→ * Removes all event listeners, styles, and resets state.
356→ * Exported for testing purposes.
357→ */
358→export function cleanup() {
359→  // Clear any pending collapse timer
360→  if (collapseTimer !== null) {
361→    clearTimeout(collapseTimer);
362→    collapseTimer = null;
363→  }
364→
365→  // Abort all event listeners managed by the controller
366→  if (eventController) {
367→    eventController.abort();
368→    eventController = null;
369→  }
370→
371→  // Remove styles
372→  const style = document.getElementById(STYLE_ID);
373→  if (style) style.remove();
374→
375→  // Remove classes from containers
376→  document.querySelectorAll(`.${COLLAPSED_CLASS}`).forEach((el) => {
377→    el.classList.remove(COLLAPSED_CLASS);
378→  });
379→  document.querySelectorAll('.element-to-collapse').forEach((el) => {
380→    el.classList.remove('element-to-collapse');
381→  });
382→  document.querySelectorAll('.gv-processed').forEach((el) => {
383→    el.classList.remove('gv-processed');
384→  });
385→  document.querySelectorAll(`.${PLACEHOLDER_CLASS}`).forEach((el) => {
386→    el.remove();
387→  });
388→
389→  // Disconnect observer
390→  if (observer) {
391→    observer.disconnect();
392→    observer = null;
393→  }
394→
395→  initialized = false;
396→}
