398→function initInputCollapse(allowCollapseNotEmpty: boolean = false) {
399→  if (initialized) return;
400→  initialized = true;
401→  allowCollapseWhenNotEmpty = allowCollapseNotEmpty; // Store the setting
402→
403→  injectStyles();
404→
405→  let lastPathname = window.location.pathname;
406→
407→  // Create AbortController for managing all event listeners
408→  eventController = new AbortController();
409→  const { signal } = eventController;
410→
411→  // Auto-expand the input area when a file is dragged into the window.
412→  document.addEventListener(
413→    'dragenter',
414→    (e) => {
415→      if (e.dataTransfer?.types.includes('Files')) {
416→        const container = getInputContainer();
417→        if (container && container.classList.contains(COLLAPSED_CLASS)) {
418→          expand(container);
419→        }
420→      }
421→    },
422→    { signal, capture: true },
423→  );
424→
425→  // Handle URL changes for SPA navigation
426→  const urlChangeHandler = () => {
427→    // Safety check for test environments and edge cases
428→    if (typeof window === 'undefined' || !window.location) return;
429→
430→    const currentPathname = window.location.pathname;
431→    if (currentPathname === lastPathname) return;
432→
433→    lastPathname = currentPathname;
434→
435→    const container = getInputContainer();
436→    if (!container) return;
437→
438→    if (shouldDisableAutoCollapse()) {
439→      // On homepage/new conversation/gems create: expand the input
440→      container.classList.remove(COLLAPSED_CLASS);
441→    } else {
442→      // On conversation page: try to collapse if appropriate
443→      tryCollapse(container);
444→    }
445→  };
446→
447→  // Listen for URL changes (browser back/forward)
448→  window.addEventListener('popstate', urlChangeHandler, { signal });
449→
450→  // MutationObserver to re-apply when Gemini re-renders and detect SPA navigation
451→  // Use MutationObserver so we re-apply if Gemini re-renders (common in SPAs)
452→  observer = new MutationObserver(() => {
453→    // Check for URL changes on DOM mutations (catches SPA navigation)
454→    urlChangeHandler?.();
455→
456→    const container = getInputContainer();
457→    if (container && !container.classList.contains('gv-processed')) {
458→      container.classList.add('gv-processed');
459→      container.classList.add('element-to-collapse'); // Add transition class
460→
461→      ensurePlaceholder(container);
462→
463→      // Events - use signal for automatic cleanup
464→      container.addEventListener(
465→        'click',
466→        () => {
467→          expand(container);
468→        },
469→        { signal },
470→      );
471→
472→      // Capture focus events deeply
473→      // focusin cancels delayed collapse when focus returns to input area
474→      container.addEventListener(
475→        'focusin',
476→        () => {
477→          expand(container);
478→          // If we have a pending collapse, cancel it since focus is coming back
479→          if (collapseTimer !== null) {
480→            clearTimeout(collapseTimer);
481→            collapseTimer = null;
482→          }
483→        },
484→        { signal },
485→      );
486→
487→      // Store container reference for use in closures
488→      const currentContainer = container;
489→
490→      container.addEventListener(
491→        'focusout',
492→        (e) => {
493→          // Clear any existing timer
494→          if (collapseTimer !== null) {
495→            clearTimeout(collapseTimer);
496→            collapseTimer = null;
497→          }
498→
499→          const newFocus = e.relatedTarget as HTMLElement;
500→
501→          // Check if focus is still inside the container
502→          if (newFocus && currentContainer.contains(newFocus)) {
503→            return; // Focus is still inside
504→          }
505→
506→          // Use a small delay before collapsing
507→          // This allows focusin events to cancel the collapse if focus returns
508→          collapseTimer = window.setTimeout(() => {
509→            // Double-check: focus should truly be away from input-related elements
510→            const active = document.activeElement as HTMLElement;
511→            if (active && currentContainer.contains(active)) {
512→              return; // Focus came back, don't collapse
513→            }
514→
515→            // Also check if the new focus is in an input-related overlay/menu
516→            if (
517→              (newFocus && isInputRelatedElement(newFocus, currentContainer)) ||
518→              (active && isInputRelatedElement(active, currentContainer))
519→            ) {
520→              return; // Focus moved to input-related UI, don't collapse
521→            }
522→
523→            // Now safe to collapse
524→            tryCollapse(currentContainer);
525→            collapseTimer = null;
526→          }, 100); // 100ms delay - enough for focusin to cancel if needed
527→        },
528→        { signal },
529→      );
530→
531→      // Initial check - only collapse if not on excluded pages
532→      if (!shouldDisableAutoCollapse()) {
533→        tryCollapse(container);
534→      }
535→    }
536→  });
537→
538→  observer.observe(document.body, { childList: true, subtree: true });
539→
540→  // Add keyboard shortcuts for collapse/expand
541→  document.addEventListener(
542→    'keydown',
543→    (e) => {
544→      const container = getInputContainer();
545→      if (!container) return;
546→
547→      // ESC key - collapse input
548→      if (e.key === 'Escape') {
549→        // Only respond when focus is within the input container
550→        const active = document.activeElement;
551→        if (active && container.contains(active)) {
552→          e.preventDefault();
553→          e.stopPropagation();
554→          collapseInput();
555→        }
556→        return;
557→      }
558→
559→      // Ctrl+I - expand input and focus with cursor at end
560→      if (e.key === 'i' || e.key === 'I') {
561→        if (e.ctrlKey || e.metaKey) {
562→          // Only respond when input is collapsed
563→          if (container.classList.contains(COLLAPSED_CLASS)) {
564→            e.preventDefault();
565→            e.stopPropagation();
566→            expandInputWithCursorAtEnd();
567→          }
568→        }
569→        return;
570→      }
571→    },
572→    { signal, capture: true }, // capture phase to ensure we intercept before other handlers
573→  );
574→
575→  // Listen for language changes and update placeholder text
576→  browser.storage.onChanged.addListener((changes, areaName) => {
577→    if ((areaName === 'sync' || areaName === 'local') && changes[StorageKeys.LANGUAGE]) {
578→      // Update all placeholder text
579→      document.querySelectorAll<HTMLDivElement>(`.${PLACEHOLDER_CLASS}`).forEach((placeholder) => {
580→        const span = placeholder.querySelector('span');
581→        if (span) {
582→          span.textContent = getTranslationSync('inputCollapsePlaceholder') || 'Message Gemini';
583→        }
584→      });
585→    }
586→  });
587→
588→  // Try once immediately
589→  const container = getInputContainer();
590→  if (container) {
591→    // trigger logic manually just in case
592→    container.classList.remove('gv-processed');
593→  }
594→}
