596→/**
597→ * Check if an element is part of input-related UI (menus, overlays, etc.)
598→ * This prevents collapse when clicking model selector, attachment button, etc.
599→ */
600→function isInputRelatedElement(element: HTMLElement, container: HTMLElement): boolean {
601→  if (!element) return false;
602→
603→  // Check if the element is or is inside known input-related containers
604→  const INPUT_RELATED_SELECTORS = [
605→    // Material/CDK overlays (menus, dialogs, autocomplete dropdowns)
606→    '.cdk-overlay-container',
607→    '.mat-mdc-menu-panel',
608→    '.mat-mdc-dialog-container',
609→    '.ng-trigger',
610→    // Model selector and related UI
611→    '[role="listbox"]',
612→    '[role="option"]',
613→    '[role="combobox"]',
614→    // Attachment and file-related UI
615→    '[data-test-id*="attachment"]',
616→    '[data-test-id*="upload"]',
617→    '[data-test-id*="file"]',
618→  ];
619→
620→  // Combine selectors into a single string for better performance
621→  const combinedSelector = INPUT_RELATED_SELECTORS.join(', ');
622→  if (element.matches(combinedSelector) || element.closest(combinedSelector)) {
623→    return true;
624→  }
625→
626→  // Additional heuristic: check if element is within a reasonable proximity
627→  // to the input container (within 5 levels up, but not the body/main)
628→  let parent = element.parentElement;
629→  let levels = 0;
630→  while (parent && levels < 5) {
631→    // If we reach body or main, we've gone too far
632→    if (parent.tagName === 'BODY' || parent.tagName === 'MAIN') {
633→      break;
634→    }
635→    // If we find the container, the element is input-related
636→    if (parent === container) {
637→      return true;
638→    }
639→    parent = parent.parentElement;
640→    levels++;
641→  }
642→
643→  return false;
644→}
