646→function expand(container: HTMLElement, moveCursorToEnd: boolean = false) {
647→  if (container.classList.contains(COLLAPSED_CLASS)) {
648→    container.classList.remove(COLLAPSED_CLASS);
649→
650→    // Auto-focus the Quill editor
651→    const editor =
652→      container.querySelector('.ql-editor') ||
653→      container.querySelector('[contenteditable]') ||
654→      container.querySelector('rich-textarea');
655→
656→    if (editor && editor instanceof HTMLElement) {
657→      setTimeout(() => {
658→        editor.focus();
659→        if (moveCursorToEnd && !isInputEmpty(container)) {
660→          moveCursorToEndOfElement(editor);
661→        }
662→      }, 0);
663→    }
664→  }
665→}
666→
667→/**
668→ * Moves the cursor to the end of the content in a contenteditable element
669→ */
670→function moveCursorToEndOfElement(element: HTMLElement): void {
671→  const selection = window.getSelection();
672→  if (!selection) return;
673→
674→  const range = document.createRange();
675→
676→  const targetNode = element.lastChild || element;
677→
678→  range.selectNodeContents(targetNode);
679→  range.collapse(false); // false = collapse to end
680→
681→  selection.removeAllRanges();
682→  selection.addRange(range);
683→}
