685→function tryCollapse(container: HTMLElement) {
686→  // We need a small delay to handle transient states
687→  setTimeout(() => {
688→    // Don't collapse on excluded pages (homepage, new conversation, gems create)
689→    if (shouldDisableAutoCollapse()) {
690→      container.classList.remove(COLLAPSED_CLASS);
691→      return;
692→    }
693→
694→    const active = document.activeElement;
695→    const isStillFocused = container.contains(active);
696→
697→    if (!isStillFocused) {
698→      // Check if we should collapse based on setting and input state
699→      // If allowCollapseWhenNotEmpty is true, we can collapse even with content
700→      // Otherwise, only collapse when empty (original behavior)
701→      const canCollapse = allowCollapseWhenNotEmpty || isInputEmpty(container);
702→      if (canCollapse) {
703→        container.classList.add(COLLAPSED_CLASS);
704→      }
705→    }
706→  }, 150);
707→}
